// Java 25 exam prep - Switch expressions
// Learn: return a value from a switch with arrows and yield.
int seasonDays(String season) {
    return switch (season) {
        case "winter", "summer" -> 93;
        case "spring" -> 92;
        case "autumn" -> {
            int base = 90;
            yield base + 1; // block arm returns with yield
        }
        default -> 0;
    };
}
